import React, { createContext, useCallback, useContext, useEffect, useRef, useState } from 'react'
import '../styles/toast.css'
import { setToastHandler } from '../utils/toastBridge'

const ToastContext = createContext(null)

export const useToast = () => {
  return useContext(ToastContext)
}

let idCounter = 1

export const ToastProvider = ({ children }) => {
  const [toasts, setToasts] = useState([])
  const timers = useRef(new Map())

  useEffect(() => {
    return () => {
      // cleanup timers
      for (const t of timers.current.values()) clearTimeout(t)
      timers.current.clear()
    }
  }, [])

  const removeToast = useCallback((id) => {
    setToasts((s) => s.filter((t) => t.id !== id))
    const t = timers.current.get(id)
    if (t) clearTimeout(t)
    timers.current.delete(id)
  }, [])

  const show = useCallback(({ title, message, type = 'info', duration = 4000 }) => {
    const id = idCounter++
    const toast = { id, title, message, type }
    setToasts((s) => [toast, ...s])

    const timer = setTimeout(() => removeToast(id), duration)
    timers.current.set(id, timer)
    return id
  }, [removeToast])

  const contextValue = {
    showToast: show,
    removeToast,
  }

  useEffect(() => {
    setToastHandler(show)
    return () => setToastHandler(null)
  }, [show])

  return (
    <ToastContext.Provider value={contextValue}>
      {children}
      <div className="toast-container">
        {toasts.map((t) => (
          <div key={t.id} className={`toast toast--${t.type}`} onClick={() => removeToast(t.id)}>
            {t.title && <div className="toast__title">{t.title}</div>}
            {t.message && <div className="toast__message">{t.message}</div>}
            <button className="toast__close" onClick={(e) => { e.stopPropagation(); removeToast(t.id) }}>×</button>
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  )
}

export default ToastProvider
